import { NextRequest } from "next/server";
import { auth } from "@/lib/auth";
import { db } from "@/lib/db";
import { messages, files } from "@/lib/db/schema";
import { eq } from "drizzle-orm";

const SYSTEM_PROMPT = `You are an expert Next.js coding assistant in a vibe coding platform. You help users build web applications using Next.js, React, TypeScript, and Tailwind CSS.

## Project Structure
Projects use the Next.js Pages Router with this structure:
- pages/index.tsx — Main page component
- pages/_app.tsx — App wrapper (imports globals.css)
- components/ — Reusable React components
- styles/globals.css — Global styles with Tailwind directives
- tailwind.config.ts — Tailwind configuration
- package.json — Dependencies (next, react, react-dom, tailwindcss, typescript)
- tsconfig.json — TypeScript config
- next.config.js — Next.js config

## Code Generation Rules

1. **Always use Next.js Pages Router patterns** — Use pages/index.tsx, pages/_app.tsx, etc. Do NOT use App Router.

2. **Always use TypeScript** — All components should be .tsx with proper TypeScript types. Use interfaces for props.

3. **Always use Tailwind CSS for styling** — Never use inline styles, CSS modules, or styled-components. Use Tailwind utility classes exclusively.

4. **Use functional components with hooks** — No class components. Use useState, useEffect, useCallback, etc.

5. **Import from next/head for metadata** — Use Head component for title, meta tags.

6. **Import from next/link for navigation** — Use Link component for client-side navigation.

7. **Component files go in components/** — Reusable components should be in the components/ directory.

8. **Use modern React patterns** — Destructure props with TypeScript interfaces, use optional chaining, handle loading/error states.

9. **For styling, use modern Tailwind patterns** — Use responsive prefixes (sm:, md:, lg:), Tailwind color palette (slate, indigo, etc.), flexbox/grid for layout, gap for spacing.

## File Output Format

When generating or modifying files, use this exact format:

FILE: /path/to/file.ext
\`\`\`language
code here
\`\`\`

Be concise but thorough. Focus on working code over explanations unless asked. Always generate complete, runnable files — never partial snippets or "..." placeholders.`;

export async function POST(req: NextRequest, { params }: { params: Promise<{ id: string }> }) {
  const session = await auth();
  if (!session?.user) return new Response("Unauthorized", { status: 401 });

  const { id: projectId } = await params;
  const { messages: chatMessages, model = "openai/gpt-4o" } = await req.json();

  const projectFiles = await db.query.files.findMany({ where: eq(files.projectId, projectId) });
  const fileContext = projectFiles.map((f) => `--- ${f.path} ---\n${f.content}`).join("\n\n");

  const messagesWithSystem = [
    { role: "system" as const, content: SYSTEM_PROMPT + "\n\nCurrent project files:\n\n" + fileContext },
    ...chatMessages,
  ];

  const apiKey = process.env.OPENAI_API_KEY || process.env.OPENROUTER_API_KEY;
  const baseUrl = process.env.OPENAI_BASE_URL || "https://openrouter.ai/api/v1";

  const response = await fetch(`${baseUrl}/chat/completions`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      Authorization: `Bearer ${apiKey}`,
      ...(baseUrl.includes("openrouter") && {
        "HTTP-Referer": process.env.NEXT_PUBLIC_APP_URL || "http://localhost:3000",
        "X-Title": "Vibe Coding Platform",
      }),
    },
    body: JSON.stringify({ model, messages: messagesWithSystem, stream: true }),
  });

  if (!response.ok) {
    return new Response(await response.text(), { status: response.status });
  }

  const reader = response.body?.getReader();
  const encoder = new TextEncoder();
  let fullContent = "";

  const stream = new ReadableStream({
    async start(controller) {
      if (!reader) {
        controller.close();
        return;
      }
      try {
        while (true) {
          const { done, value } = await reader.read();
          if (done) break;
          const text = new TextDecoder().decode(value);
          const lines = text.split("\n").filter((l) => l.startsWith("data: "));
          for (const line of lines) {
            const data = line.replace("data: ", "");
            if (data === "[DONE]") continue;
            try {
              const parsed = JSON.parse(data);
              const delta = parsed.choices?.[0]?.delta?.content || "";
              fullContent += delta;
              controller.enqueue(encoder.encode(delta));
            } catch {}
          }
        }
      } finally {
        try {
          const lastUserMsg = chatMessages[chatMessages.length - 1];
          await db.insert(messages).values([
            { projectId, role: "user", content: lastUserMsg.content },
            { projectId, role: "assistant", content: fullContent },
          ]);
        } catch {}
        controller.close();
      }
    },
  });

  return new Response(stream, {
    headers: { "Content-Type": "text/plain; charset=utf-8", "Cache-Control": "no-cache" },
  });
}
